local B=dofile("languages/lua/brush.lua");local function p(x,y)return{x=x,y=y}end;local points={}for _,v in ipairs{{500,520},{450,450},{390,395},{320,370},{250,370},{180,390},{130,450},{120,520},{155,585},{220,635},{300,650},{380,620},{440,570},{500,520},{560,465},{620,410},{700,370},{770,380},{830,420},{870,480},{875,545},{845,610},{790,660},{720,675},{650,655},{585,610},{540,560},{500,520}}do points[#points+1]=p(v[1],v[2])end;assert(B.build_rounded_drawing_path({p(0,0),p(100,0),p(100,100)},40)=="M 0 0 L 55 0 Q 100 0 100 45 L 100 100");assert(B.sample_at(B.prepare_arc_length_path({p(0,0),p(100,0)}),.5).angle==0);local input=arg[1]or"assets/example.webp";local output=arg[2]or"generated/lua.svg";local f=assert(io.open(input,"rb"));local bytes=f:read("*a");f:close();local svg=B.render_svg(bytes,"image/webp",1000,1000,points,"🤝 best friends forever",{font_size=40,magic_gradient=true});f=assert(io.open(output,"wb"));f:write(svg);f:close();print("Wrote "..output)
